import time
import can
import pytest

GW_DOOR_STATUS_ID = 0x10E
GW_DOOR_STATUS_DLC = 8

@pytest.fixture(scope="module")
def can_bus():
    bus = can.Bus(interface="vector", channel=0, bitrate=500000)
    yield bus
    bus.shutdown()

def collect_messages(bus, msg_id, duration_sec):
    messages = []
    start_time = time.time()
    while time.time() - start_time < duration_sec:
        msg = bus.recv(timeout=0.5)
        if msg and msg.arbitration_id == msg_id:
            messages.append(msg)
    return messages

def decode_door_fl(msg):
    return (msg.data[0] >> 0) & 0x01

def decode_door_fr(msg):
    return (msg.data[0] >> 1) & 0x01

def decode_door_rl(msg):
    return (msg.data[0] >> 2) & 0x01

def decode_door_rr(msg):
    return (msg.data[0] >> 3) & 0x01

def decode_any_door_open(msg):
    return (msg.data[0] >> 4) & 0x01

