def test_tc_gw_door_004_fr_open(can_bus):
    msgs = collect_messages(can_bus, GW_DOOR_STATUS_ID, 2)
    assert msgs, 'No GW_DoorStatus messages received'
    for msg in msgs:
        assert decode_door_fr(msg) == 1
        assert decode_any_door_open(msg) == 1

def test_tc_gw_door_005_rl_open(can_bus):
    msgs = collect_messages(can_bus, GW_DOOR_STATUS_ID, 2)
    assert msgs, 'No GW_DoorStatus messages received'
    for msg in msgs:
        assert decode_door_rl(msg) == 1
        assert decode_any_door_open(msg) == 1

def test_tc_gw_door_006_rr_open(can_bus):
    msgs = collect_messages(can_bus, GW_DOOR_STATUS_ID, 2)
    assert msgs, 'No GW_DoorStatus messages received'
    for msg in msgs:
        assert decode_door_rr(msg) == 1
        assert decode_any_door_open(msg) == 1

def test_tc_gw_door_007_multiple_doors_open(can_bus):
    msgs = collect_messages(can_bus, GW_DOOR_STATUS_ID, 2)
    assert msgs, 'No GW_DoorStatus messages received'
    for msg in msgs:
        assert decode_any_door_open(msg) == 1

def test_tc_gw_door_008_dlc_check(can_bus):
    msgs = collect_messages(can_bus, GW_DOOR_STATUS_ID, 2)
    assert msgs, 'No GW_DoorStatus messages received'
    for msg in msgs:
        assert msg.dlc == GW_DOOR_STATUS_DLC
